"use client"
import * as React from "react"
import { cn } from "@/lib/utils"

interface SpotlightHeroProps {
  headline: React.ReactNode
  subtext?: string
  cta?: { label: string; href: string; primary?: boolean }[]
  className?: string
}

export function SpotlightHero({ headline, subtext, cta = [], className }: SpotlightHeroProps) {
  const ref = React.useRef<HTMLDivElement>(null)
  const [pos, setPos] = React.useState({ x: "50%", y: "30%" })

  const onMove = (e: React.MouseEvent) => {
    const rect = ref.current!.getBoundingClientRect()
    setPos({
      x: `${((e.clientX - rect.left) / rect.width) * 100}%`,
      y: `${((e.clientY - rect.top) / rect.height) * 100}%`,
    })
  }

  return (
    <section
      ref={ref}
      onMouseMove={onMove}
      className={cn("relative flex min-h-svh items-center justify-center overflow-hidden bg-[#030303]", className)}
    >
      {/* Dot grid */}
      <div
        className="pointer-events-none absolute inset-0"
        style={{
          backgroundImage: `radial-gradient(circle, rgba(255,255,255,0.15) 1px, transparent 1px)`,
          backgroundSize: "40px 40px",
          maskImage: `radial-gradient(ellipse 80% 80% at ${pos.x} ${pos.y}, black 30%, transparent 80%)`,
          WebkitMaskImage: `radial-gradient(ellipse 80% 80% at ${pos.x} ${pos.y}, black 30%, transparent 80%)`,
        }}
      />
      {/* Glow orb */}
      <div
        className="pointer-events-none absolute h-96 w-96 rounded-full opacity-20 blur-[80px] transition-all duration-200"
        style={{
          background: "#00d4ff",
          left: `calc(${pos.x} - 12rem)`,
          top: `calc(${pos.y} - 12rem)`,
        }}
      />
      <div className="relative z-10 mx-auto max-w-4xl px-6 text-center">
        <h1 className="text-5xl font-bold tracking-[-0.04em] sm:text-7xl">{headline}</h1>
        {subtext && <p className="mt-6 text-lg text-[#555] max-w-xl mx-auto">{subtext}</p>}
        {cta.length > 0 && (
          <div className="mt-10 flex flex-wrap justify-center gap-3">
            {cta.map(c => (
              <a
                key={c.href} href={c.href}
                className={c.primary
                  ? "rounded-full bg-white px-7 py-3 text-sm font-semibold text-black hover:bg-[#e2e2e2] transition-colors"
                  : "rounded-full border border-white/[0.1] px-7 py-3 text-sm font-medium text-[#777] hover:text-white transition-colors"
                }
              >
                {c.label}
              </a>
            ))}
          </div>
        )}
      </div>
    </section>
  )
}
